-- [ ObfusPro+ ]
local dYrrG = bit32 or bit or error("ObfusPro+: Environment error");
local function vzNzHn(BnNOl)
    local FKftEwDG = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
    local KLxZD = string.gsub(BnNOl, '[^' .. FKftEwDG .. ']', '')
    local uMwqsWV = {}
    for OpTF = 1, #KLxZD, 4 do
        local aBq, YxX, kJT, Lbi = string.byte(KLxZD, OpTF, OpTF + 3)
        if not aBq then break end
        local LlNq = string.find(FKftEwDG, string.char(aBq)) - 1
        local VFxw = string.find(FKftEwDG, string.char(YxX)) - 1
        local gUYG = kJT and string.find(FKftEwDG, string.char(kJT)) - 1 or 0
        local xzyj = Lbi and string.find(FKftEwDG, string.char(Lbi)) - 1 or 0
        local KVye = LlNq * 262144 + VFxw * 4096 + gUYG * 64 + xzyj
        local Suzk = dYrrG.band(dYrrG.rshift(KVye, 16), 255)
        table.insert(uMwqsWV, string.char(dYrrG.bxor(Suzk, 108)))
        if kJT and string.char(kJT) ~= '=' then
            Suzk = dYrrG.band(dYrrG.rshift(KVye, 8), 255)
            table.insert(uMwqsWV, string.char(dYrrG.bxor(Suzk, 108)))
        end
        if Lbi and string.char(Lbi) ~= '=' then
            Suzk = dYrrG.band(KVye, 255)
            table.insert(uMwqsWV, string.char(dYrrG.bxor(Suzk, 108)))
        end
    end
    return table.concat(uMwqsWV)
end
local DiCKoN = math.sin(482);
